(window.webpackJsonp=window.webpackJsonp||[]).push([[25],{310:function(e,n,t){"use strict";t.r(n);var a=t(14),o=Object(a.a)({},(function(){var e=this,n=e._self._c;return n("ContentSlotsDistributor",{attrs:{"slot-key":e.$parent.slotKey}},[n("details",[n("summary",[n("strong",[e._v("Skills")])]),e._v(" "),n("div",{staticStyle:{"padding-left":"1.5em"}},[n("br"),e._v(" "),n("p",[e._v("Skills are domain knowledge files the agent loads on-demand before working on a specific area of your codebase. Each skill documents the patterns, conventions, and rules for a particular concern — how to write an interactor, how to structure a DTO, how to handle datetime values.")]),e._v(" "),n("p",[e._v("Skills are not injected into every request — they are loaded only when the task touches the relevant domain, keeping the context window focused.")])])]),e._v(" "),n("br"),e._v(" "),n("details",[n("summary",[n("strong",[e._v("Commands")])]),e._v(" "),n("div",{staticStyle:{"padding-left":"1.5em"}},[n("br"),e._v(" "),n("p",[e._v("Commands are slash-command recipes that define the agent's goal and process for a specific type of task. When you invoke a command, the agent switches into a structured mode — it knows what kind of thinking to do, what steps to follow, and what the output should look like.")])])]),e._v(" "),n("br"),e._v(" "),n("details",[n("summary",[n("strong",[e._v("Rules")])]),e._v(" "),n("div",{staticStyle:{"padding-left":"1.5em"}},[n("br"),e._v(" "),n("p",[e._v("Rules are always-apply/pattern based guidelines that are injected into every agent session. They define the core behavior that must hold regardless of the task — how to use tools, what scope to stay within, naming conventions to follow, and how to interact with you as the developer.")]),e._v(" "),n("p",[e._v("Unlike skills (loaded on-demand) and commands (invoked explicitly), rules are passive. The agent never has to be told to follow them — they are always present. This makes them the right place for non-negotiable standards that should never be bypassed.")])])]),e._v(" "),n("br"),e._v(" "),n("details",[n("summary",[n("strong",[e._v("Hooks")])]),e._v(" "),n("div",{staticStyle:{"padding-left":"1.5em"}},[n("br"),e._v(" "),n("p",[e._v("Hooks are shell scripts that fire at specific lifecycle events during an agent session — before a shell command executes or before a tool is used. They act as hard guardrails that enforce constraints the agent cannot bypass, even if instructed to.")]),e._v(" "),n("p",[e._v("The difference between hooks and rules is enforcement: rules guide the agent's behavior through instructions, hooks enforce constraints through code. A hook can physically block a destructive command from running, prevent writes outside the workspace, or check code patterns before a push.")]),e._v(" "),n("p",[n("strong",[e._v("Examples")]),e._v(": blocking "),n("code",[e._v("rm")]),e._v(" and destructive shell commands, blocking writes outside the project, preventing pushes to protected branches, checking for anti-patterns before commit")])])]),e._v(" "),n("br"),e._v(" "),n("details",[n("summary",[n("strong",[e._v("Sub-Agents")])]),e._v(" "),n("div",{staticStyle:{"padding-left":"1.5em"}},[n("br"),e._v(" "),n("p",[e._v("Sub-agents are spawned by the main agent to handle isolated, parallelizable work. When a task involves deep research across independent areas — like scanning multiple parts of the codebase simultaneously — the main agent can delegate each area to a sub-agent and get back focused results without doing all the work sequentially.")]),e._v(" "),n("p",[e._v("Sub-agents run in their own context with a fresh scope. They do not share the main session's conversation history and only return the specific output the main agent asked for. This keeps the main context lean while still covering broad ground.")]),e._v(" "),n("p",[e._v("Sub-agents are used sparingly — only when parallel research genuinely saves time. For most tasks, the main agent handles everything directly.")])])]),e._v(" "),n("br"),e._v(" "),n("details",[n("summary",[n("strong",[e._v("MCPs (Model Context Protocol)")])]),e._v(" "),n("div",{staticStyle:{"padding-left":"1.5em"}},[n("br"),e._v(" "),n("p",[e._v("MCPs are external tool integrations that extend what the agent can do beyond reading and writing code. They give the agent access to live data and external systems — like capturing Figma design screenshots, navigating a browser, or querying an issue tracker — when the task requires it.")]),e._v(" "),n("p",[e._v("MCPs are not always-on. Enabling all MCPs in every session consumes context window tokens with tool definitions that may be irrelevant to the current task. The right approach is to enable only the MCPs relevant to what you're working on.")])])]),e._v(" "),n("details",[n("summary",[n("strong",[e._v("What is a Good PRD?")])]),e._v(" "),n("div",{staticStyle:{"padding-left":"1.5em"}},[n("br"),e._v(" "),n("ul",[n("li",[e._v("\nThere should be no conflicting flows/cases in the PRD.\n")]),e._v(" "),n("li",[e._v("\nThere should be no missing flows/cases in the PRD.\n")]),e._v(" "),n("li",[e._v("\nThere should be no unexplained or assumed flows/cases in the PRD.\n")]),e._v(" "),n("li",[e._v("\nHaving only relevant details for the task in the PRD.\n")])])])]),e._v(" "),n("details",[n("summary",[n("strong",[e._v("Common Mistakes")])]),e._v(" "),n("div",{staticStyle:{"padding-left":"1.5em"}},[n("br"),e._v(" "),n("ul",[n("li",[e._v("\nGiving conflicting instructions/context to the Agent that contradict what is written in the PRD\n")]),e._v(" "),n("li",[e._v("\nGiving irrelevant content like success metrics, DA team notes, or other task-irrelevant content to the Agent.\n")]),e._v(" "),n("li",[e._v("\nMissing explanation of frontend behavior when it's relevant to the task flow\n")]),e._v(" "),n("li",[e._v("\nIf the PRD contains a lot of frontend sections and only part of the content is backend-relevant, giving the entire PRD to the Agent will cause it to process all frontend-relevant requirements that are not needed.\n")]),e._v(" "),n("li",[e._v("\nNot giving any extra architectural context or pointing to reference implementations when you already know the direction of implementation\n")]),e._v(" "),n("li",[e._v("\nIntentionally excluding context from the Agent to see if it figures it out from the codebase. (This causes it to spend more time on the task and reduces efficiency)\n")]),e._v(" "),n("li",[e._v("\nNot mentioning external integration request/response contracts beforehand.\n    e.g., Sheet utils, IB Users, or other external API calls.\n")]),e._v(" "),n("li",[e._v("\nNot mentioning the task depends on any external service/package when you already know it.\n")]),e._v(" "),n("li",[e._v("\nNot mentioning when you already have a plan or implementation cases or flow\n")])])])]),e._v(" "),n("details",[n("summary",[n("strong",[e._v("Agent Input Format")])]),e._v(" "),n("div",{staticStyle:{"padding-left":"1.5em"}},[n("br"),e._v(" "),n("p",[e._v("Remove the "),n("code",[e._v("Example")]),e._v(" Heading and its content when giving to the Agent.")]),e._v(" "),n("div",{staticStyle:{position:"relative"}},[n("button",{staticStyle:{position:"absolute",top:"8px",right:"8px",padding:"4px 10px","font-size":"12px",cursor:"pointer",background:"#3eaf7c",color:"#fff",border:"none","border-radius":"4px","z-index":"10"},attrs:{type:"button",onclick:"var t=this.nextElementSibling;navigator.clipboard.writeText(t.value).then(function(){},function(){});var b=this;b.textContent='Copied!';setTimeout(function(){b.textContent='Copy'},2000)"}},[e._v("Copy")]),e._v(" "),n("textarea",{staticStyle:{display:"block",width:"100%","box-sizing":"border-box",background:"#282c34",color:"#abb2bf",padding:"2.5em 1em 1.2em 1em",border:"none","border-radius":"6px","font-family":"monospace","font-size":"13px","line-height":"1.6",resize:"vertical","min-height":"420px","white-space":"pre",overflow:"auto"},attrs:{readonly:""}},[e._v('# Requirement Format\n<h2 id="_1-core-requirement"><a class="header-anchor" href="#_1-core-requirement">#</a> 1. Core Requirement</h2>\n<p><strong>What are we building?</strong></p>\n<p><strong>Example:</strong></p>\n<p>Build an API endpoint to fetch user\'s completed learning units. The API should return a list of units the user has completed, along with completion timestamps and scores if available.</p>\n<hr>\n<h2 id="_2-architectural-context"><a class="header-anchor" href="#_2-architectural-context">#</a> 2. Architectural Context</h2>\n<p><strong>Where does this code live and why? Are there existing patterns or structures to follow?</strong></p>\n<p><strong>Example:</strong></p>\n<p>This belongs in nkb_resources app because it deals with learning unit data. Follow the existing view structure in nkb_resources/views/. There\'s already a get_user_resources_v1 pattern we should mirror. Storage layer should use the ResourceStorage class.</p>\n<hr>\n<h2 id="_3-frontend-ui-context"><a class="header-anchor" href="#_3-frontend-ui-context">#</a> 3. Frontend/UI Context</h2>\n<p><strong>Client-side behavior that affects backend</strong></p>\n<p><strong>Example:</strong></p>\n<p>Mobile app displays this in a timeline view and expects data sorted by completion_date DESC. The app caches this data for 5 minutes, so include a last_updated timestamp. Frontend expects empty array if no data, not null.</p>\n<p>it will auto navigate to another tab and they will call x api</p>\n<hr>\n<h2 id="_4-external-systems-integrations"><a class="header-anchor" href="#_4-external-systems-integrations">#</a> 4. External Systems & Integrations</h2>\n<p><strong>What external projects, services, or APIs does this interact with?</strong></p>\n<p><strong>Example:</strong></p>\n<p>This needs to call the analytics service (nkb_analytics project) to log completion events. Use the existing AnalyticsClient in common/clients/. Also, when a user completes a unit, we send a webhook to the notification service (runs separately on port 8001).</p>\n<hr>\n<h2 id="_5-misc"><a class="header-anchor" href="#_5-misc">#</a> 5. Misc</h2>\n<p><strong>What are we assuming? Any decisions, gotchas, or special context?</strong></p>\n<p><strong>Example:</strong></p>\n<ul>\n<li>\n<p>User can only see their own completed units, not others</p>\n</li>\n<li>\n<p>Don\'t use the old CompletionLog model, it\'s deprecated. Use UserUnitProgress instead.</p>\n</li>\n<li>\n<p>This query can be slow for power users (1000+ completions), so add pagination\n')])]),n("p")])]),e._v(" "),n("details",[n("summary",[n("strong",[e._v("PRD Format Example")])]),e._v(" "),n("div",{staticStyle:{"padding-left":"1.5em"}},[n("br"),e._v(" "),n("div",{staticStyle:{position:"relative"}},[n("button",{staticStyle:{position:"absolute",top:"8px",right:"8px",padding:"4px 10px","font-size":"12px",cursor:"pointer",background:"#3eaf7c",color:"#fff",border:"none","border-radius":"4px","z-index":"10"},attrs:{type:"button",onclick:"var t=this.nextElementSibling;navigator.clipboard.writeText(t.value).then(function(){},function(){});var b=this;b.textContent='Copied!';setTimeout(function(){b.textContent='Copy'},2000)"}},[e._v("Copy")]),e._v(" "),n("textarea",{staticStyle:{display:"block",width:"100%","box-sizing":"border-box",background:"#282c34",color:"#abb2bf",padding:"2.5em 1em 1.2em 1em",border:"none","border-radius":"6px","font-family":"monospace","font-size":"13px","line-height":"1.6",resize:"vertical","min-height":"800px","white-space":"pre",overflow:"auto"},attrs:{readonly:""}},[e._v('# Application Fee Discount Offer\n<h2 id="problem-statement"><a class="header-anchor" href="#problem-statement">#</a> Problem Statement</h2>\n<p>Application portal shows significant delay and drop-off between OTP verification and application fee payment, especially within the first 30 minutes. Users complete OTP (demonstrating high intent) but delay or abandon before paying. The gap allows distraction, second thoughts, and loss of momentum. Currently no immediate incentive to act right after login.</p>\n<p><strong>Opportunity:</strong> First 30 minutes post-login is the highest intent moment. Introduce one-time incentive to convert intent into immediate action. Expected impact: improve OTP → payment conversion, shift more payments into 0-30 min window, faster revenue realization, lower re-marketing dependency.</p>\n<hr>\n<h2 id="solution-goal"><a class="header-anchor" href="#solution-goal">#</a> Solution (Goal)</h2>\n<p>Offer users a one-time discount immediately when they first log in to encourage completing payment right away.</p>\n<hr>\n<h2 id="pre-context-omit-if-not-applicable"><a class="header-anchor" href="#pre-context-omit-if-not-applicable">#</a> Pre Context (Omit if not applicable)</h2>\n<ul>\n<li>Application is already created (via phone flow or portal)</li>\n<li>Payment flow exists where users pay application fee</li>\n</ul>\n<p><strong>Starting State:</strong>\nUser just logged in for the first time and is about to see the personal details page.</p>\n<hr>\n<h2 id="key-terms"><a class="header-anchor" href="#key-terms">#</a> Key Terms</h2>\n<p><strong>NIAT_200</strong> - Our promotional discount code offering ₹200 off the application fee</p>\n<p><strong>Application Fee</strong> - The ₹1200 fee users pay to submit their application</p>\n<p><strong>Discount Available</strong> - User has access to a discount code but it\'s not currently reducing the fee amount (fee displays ₹1200)</p>\n<p><strong>Discount Applied</strong> - Discount is active and fee displays the reduced amount (₹1000 instead of ₹1200)</p>\n<p><strong>Discount Used</strong> - User completed payment successfully with discount. That specific code cannot be used again by this user.</p>\n<p><strong>One-time</strong> - Each discount code can only be used once per user. After payment succeeds with that code, it\'s permanently consumed.</p>\n<p><strong>First Login</strong> - The very first time a user logs in after completing OTP for this application</p>\n<hr>\n<h2 id="user-journeys"><a class="header-anchor" href="#user-journeys">#</a> User Journeys</h2>\n<h3 id="journey-1-user-arrives-without-coupon-clicks-copy"><a class="header-anchor" href="#journey-1-user-arrives-without-coupon-clicks-copy">#</a> Journey 1: User Arrives Without Coupon, Clicks "Copy"</h3>\n<h4 id="what-user-sees"><a class="header-anchor" href="#what-user-sees">#</a> What User Sees</h4>\n<ul>\n<li>Personal details page loads</li>\n<li>Popup appears immediately showing:\n<ul>\n<li>Heading "Offer Unlocked!"</li>\n<li>Discount code "NIAT_200"</li>\n<li>Message "Get ₹200 OFF on your application fee"</li>\n<li>"Copy" button</li>\n<li>"×" close icon at top-right</li>\n</ul>\n</li>\n</ul>\n<h4 id="what-user-can-do"><a class="header-anchor" href="#what-user-can-do">#</a> What User Can Do</h4>\n<ul>\n<li>Click "Copy" button to copy code</li>\n<li>Click "×" to close popup</li>\n<li>Ignore and continue to form</li>\n</ul>\n<h4 id="what-happens-next"><a class="header-anchor" href="#what-happens-next">#</a> What Happens Next</h4>\n<p><strong>User clicks "Copy":</strong></p>\n<ul>\n<li>Code "NIAT_200" copies to clipboard</li>\n<li>Popup shows "Copied!" confirmation next to the code</li>\n<li>Popup can be closed</li>\n<li>User fills personal details and continues through application</li>\n<li>When user reaches payment page later:\n<ul>\n<li>Fee breakdown shows "Application Fee: ₹1200"</li>\n<li>Discount line shows "Discount (NIAT_200): -₹200"</li>\n<li>Total shows "Amount to Pay: ₹1000"</li>\n<li>"Clear" link appears next to discount</li>\n</ul>\n</li>\n<li>User can proceed to payment or clear the discount</li>\n</ul>\n<h4 id="rules"><a class="header-anchor" href="#rules">#</a> Rules</h4>\n<ul>\n<li>Popup appears only on first login for this application</li>\n<li>If user logs out and logs back in later, popup does not appear again</li>\n<li>Clicking "Copy" makes the discount automatically applied at payment (user doesn\'t manually enter code)</li>\n<li>Discount state is consistent across all devices (phone, laptop, tablet)</li>\n</ul>\n<hr>\n<h3 id="journey-2-user-arrives-without-coupon-clicks-×"><a class="header-anchor" href="#journey-2-user-arrives-without-coupon-clicks-×">#</a> Journey 2: User Arrives Without Coupon, Clicks "×"</h3>\n<h4 id="what-user-sees-2"><a class="header-anchor" href="#what-user-sees-2">#</a> What User Sees</h4>\n<ul>\n<li>Personal details page loads</li>\n<li>Popup appears immediately showing:\n<ul>\n<li>Heading "Offer Unlocked!"</li>\n<li>Discount code "NIAT_200"</li>\n<li>Message "Get ₹200 OFF on your application fee"</li>\n<li>"Copy" button</li>\n<li>"×" close icon at top-right</li>\n</ul>\n</li>\n</ul>\n<h4 id="what-user-can-do-2"><a class="header-anchor" href="#what-user-can-do-2">#</a> What User Can Do</h4>\n<ul>\n<li>Click "×" to dismiss popup</li>\n<li>Ignore and continue to form</li>\n</ul>\n<h4 id="what-happens-next-2"><a class="header-anchor" href="#what-happens-next-2">#</a> What Happens Next</h4>\n<p><strong>User clicks "×":</strong></p>\n<ul>\n<li>Popup closes immediately</li>\n<li>User fills personal details and continues through application</li>\n<li>When user reaches payment page later:\n<ul>\n<li>Fee shows "Application Fee: ₹1200"</li>\n<li>Total shows "Amount to Pay: ₹1200" (no discount applied)</li>\n<li>Below fee section, a discount card appears:\n<ul>\n<li>Shows "Get ₹200 OFF"</li>\n<li>Shows "Code: NIAT_200"</li>\n<li>Has "Apply" button</li>\n</ul>\n</li>\n<li>Coupon input box is available for manual entry</li>\n</ul>\n</li>\n<li>User can click "Apply" on card or manually enter code</li>\n</ul>\n<h4 id="rules-2"><a class="header-anchor" href="#rules-2">#</a> Rules</h4>\n<ul>\n<li>Popup appears only on first login for this application</li>\n<li>If user logs out and logs back in later, popup does not appear again (discount card still available at payment)</li>\n<li>Clicking "×" does not remove discount eligibility, just means it\'s not automatically applied</li>\n<li>Discount remains available to apply manually at payment page anytime before payment succeeds</li>\n</ul>\n<hr>\n<h3 id="journey-3-user-arrives-with-coupon-in-url"><a class="header-anchor" href="#journey-3-user-arrives-with-coupon-in-url">#</a> Journey 3: User Arrives With Coupon in URL</h3>\n<h4 id="what-user-sees-3"><a class="header-anchor" href="#what-user-sees-3">#</a> What User Sees</h4>\n<ul>\n<li>User clicks link with coupon parameter: <code>www.app.com/?coupon=NAT400</code></li>\n<li>Completes OTP if needed, then logs in</li>\n<li>Personal details page loads</li>\n<li><strong>No popup appears</strong> (different from Journey 1 and 2)</li>\n<li>User sees regular personal details form</li>\n</ul>\n<h4 id="what-user-can-do-3"><a class="header-anchor" href="#what-user-can-do-3">#</a> What User Can Do</h4>\n<ul>\n<li>Fill personal details and continue through application sections</li>\n<li>Navigate to payment page</li>\n</ul>\n<h4 id="what-happens-next-3"><a class="header-anchor" href="#what-happens-next-3">#</a> What Happens Next</h4>\n<p><strong>User progresses through application:</strong></p>\n<ul>\n<li>User fills personal details, uploads documents, completes other sections</li>\n<li>No popup interruption</li>\n<li>When user reaches payment page:\n<ul>\n<li>Fee breakdown shows "Application Fee: ₹1200"</li>\n<li>Discount line shows "Discount (NAT400): -₹400" (discount from URL coupon)</li>\n<li>Total shows "Amount to Pay: ₹800"</li>\n<li>"Clear" link appears next to discount</li>\n</ul>\n</li>\n</ul>\n<p><strong>If user clicks "Clear":</strong></p>\n<ul>\n<li>Discount is removed</li>\n<li>Fee reverts to "Amount to Pay: ₹1200"</li>\n<li>Discount card appears below showing:\n<ul>\n<li>"Get ₹200 OFF"</li>\n<li>"Code: NIAT_200"</li>\n<li>"Apply" button</li>\n</ul>\n</li>\n<li>User can now apply NIAT_200 or re-apply NAT400</li>\n<li>User can switch between coupons multiple times before payment</li>\n</ul>\n<h4 id="rules-3"><a class="header-anchor" href="#rules-3">#</a> Rules</h4>\n<ul>\n<li>When URL contains coupon parameter, popup is never shown</li>\n<li>URL coupon is automatically applied at payment page</li>\n<li>Our standard NIAT_200 offer is still available if user clears the URL coupon</li>\n<li>User can only have one coupon active at a time (cannot apply both simultaneously)</li>\n</ul>\n<hr>\n<h2 id="edge-cases-special-situations"><a class="header-anchor" href="#edge-cases-special-situations">#</a> Edge Cases & Special Situations</h2>\n<h3 id="payment-gateway-timeout-or-failure"><a class="header-anchor" href="#payment-gateway-timeout-or-failure">#</a> Payment Gateway Timeout or Failure</h3>\n<p><strong>Situation:</strong> User clicks "Pay Now" but payment gateway times out, fails, or shows error</p>\n<p><strong>What Happens:</strong></p>\n<ul>\n<li>User returns to payment page (either automatically or manually)</li>\n<li>Discount still shows as applied if it was active before payment attempt</li>\n<li>User can retry payment immediately with same discount</li>\n<li>User can also clear discount and re-apply if needed</li>\n<li>Discount is only marked as "used" when payment is confirmed successful by gateway</li>\n</ul>\n<p><strong>Key Point:</strong> Technical payment failures or gateway issues do not consume the discount</p>\n<hr>\n<h3 id="invalid-url-coupon"><a class="header-anchor" href="#invalid-url-coupon">#</a> Invalid URL Coupon</h3>\n<p><strong>Situation:</strong> User clicks link with coupon that doesn\'t exist or is expired: <code>www.app.com/?coupon=INVALID123</code></p>\n<p><strong>What Happens:</strong></p>\n<ul>\n<li>No popup shows (because URL contains coupon parameter)</li>\n<li>User fills application sections normally</li>\n<li>When user reaches payment page: System attempts to auto-apply INVALID123</li>\n<li>Error message appears: "Invalid or expired code"</li>\n<li>Discount card appears below showing NIAT_200 as alternative option</li>\n<li>User can apply NIAT_200 from the card</li>\n</ul>\n<p><strong>Key Point:</strong> Invalid coupons from URL don\'t break the flow. Standard offer is still available as fallback.</p>\n<hr>\n<h3 id="user-tries-already-used-coupon"><a class="header-anchor" href="#user-tries-already-used-coupon">#</a> User Tries Already-Used Coupon</h3>\n<p><strong>Situation:</strong> User manually enters a coupon code they already used in a previous successful payment</p>\n<p><strong>What Happens:</strong></p>\n<ul>\n<li>User types the code in coupon input box</li>\n<li>Clicks "Apply"</li>\n<li>Error message appears: "This code has already been used"</li>\n<li>Fee remains at ₹1200 (no discount applied)</li>\n<li>User must enter a different valid code or proceed without discount</li>\n</ul>\n<p><strong>Key Point:</strong> Each coupon code can only be successfully used once per user\n')])]),n("p")])])])}),[],!1,null,null,null);n.default=o.exports}}]);